const payload = $json.body && typeof $json.body === 'object' ? $json.body : $json;

function pick(...values) {
  return values.find((value) => value !== undefined && value !== null && String(value).trim() !== '');
}

function cleanPath(value) {
  return String(value || '').trim().replace(/^\/+/, '');
}

function cleanDir(value, fallback) {
  return String(value || fallback).trim().replace(/^\/+|\/+$/g, '');
}

function slug(value) {
  return String(value || 'output')
    .replace(/\.[^.]+$/, '')
    .replace(/^APPROVED_/i, '')
    .replace(/^PRD_/i, '')
    .replace(/\s+/g, '_')
    .replace(/[^A-Za-z0-9가-힣_-]+/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_+|_+$/g, '') || 'output';
}

function timestamp() {
  const d = new Date();
  const yy = String(d.getFullYear()).slice(-2);
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  const hh = String(d.getHours()).padStart(2, '0');
  const mi = String(d.getMinutes()).padStart(2, '0');
  const ss = String(d.getSeconds()).padStart(2, '0');
  return `${yy}${mm}${dd}_${hh}${mi}${ss}`;
}

const allowedTypes = ['service_scenario', 'service_policy', 'ia', 'service_diagram'];
const targetOutputType = pick(payload.targetOutputType, 'service_scenario');
if (!allowedTypes.includes(targetOutputType)) throw new Error(`Unsupported targetOutputType: ${targetOutputType}`);

const prdMarkdown = pick(payload.prdMarkdown, payload.prdContent, payload.content, '');
if (!String(prdMarkdown).trim()) throw new Error('prdMarkdown is required');

const sourcePrdPath = cleanPath(payload.sourcePrdPath || 'approved-prd/manual.md');
const sourcePrdName = slug(pick(payload.sourcePrdName, sourcePrdPath.split('/').pop(), 'approved_prd'));
const ts = timestamp();

const config = {
  service_scenario: { dir: 'scenario', prefix: 'SCN', ext: 'md', contentType: 'text/markdown; charset=utf-8', prompt: 'prompts/output/scenario/scenario-prompt-v1.md' },
  service_policy: { dir: 'policy', prefix: 'POLICY', ext: 'md', contentType: 'text/markdown; charset=utf-8', prompt: 'prompts/output/policy/policy-prompt-v1.md' },
  ia: { dir: 'ia', prefix: 'IA', ext: 'csv', contentType: 'text/csv; charset=utf-8', prompt: 'prompts/output/ia/ia-prompt-v1.md' },
  service_diagram: { dir: 'diagram', prefix: 'DIAGRAM', ext: 'drawio', contentType: 'application/xml; charset=utf-8', prompt: 'prompts/output/diagram/drawio-diagram-prompt-v1.md' }
}[targetOutputType];

const outputDir = cleanDir(pick(payload.outputDir, payload[`${targetOutputType}Dir`]), config.dir);
const outputFileName = `${config.prefix}_${sourcePrdName}_${ts}.${config.ext}`;
const outputPath = `${outputDir}/${outputFileName}`;
const promptTemplate = cleanPath(pick(payload.promptTemplate, payload.promptTemplateUrl && new URL(payload.promptTemplateUrl).pathname, config.prompt));
const targetRegions = Array.isArray(payload.targetRegions) && payload.targetRegions.length ? payload.targetRegions : ['KR', 'US-CA', 'EU', 'UK', 'JP'];
const supportedLanguages = Array.isArray(payload.supportedLanguages) && payload.supportedLanguages.length ? payload.supportedLanguages : ['ko', 'en', 'ja'];

return [{ json: {
  action: 'agent2_output_generate',
  targetOutputType,
  sourcePrdPath,
  sourcePrdName,
  prdMarkdown: String(prdMarkdown).trim(),
  serviceScenarioPath: cleanPath(payload.serviceScenarioPath),
  serviceType: pick(payload.serviceType, 'global_b2c_web_promotion'),
  targetRegions,
  supportedLanguages,
  outputLanguage: pick(payload.outputLanguage, 'ko'),
  promptTemplate,
  promptTemplateType: pick(payload.promptTemplateType, targetOutputType),
  businessPolicyOverrides: payload.businessPolicyOverrides || {},
  regionPolicyMatrix: payload.regionPolicyMatrix || [],
  requestedBy: pick(payload.requestedBy, 'web'),
  model: pick(payload.model, 'gpt-4o-mini'),
  temperature: Number(payload.temperature ?? 0.2),
  maxTokens: Number(payload.maxTokens || 12000),
  vercelBaseUrl: String(pick(payload.vercelBaseUrl, payload.baseUrl, 'https://howardchoi-nsus-pocax.vercel.app')).replace(/\/+$/, ''),
  outputPath,
  outputFileName,
  outputDir,
  outputContentType: config.contentType,
  logPath: `logs/AGENT2_${config.prefix}_${sourcePrdName}_${ts}.json`,
  timestamp: ts,
  receivedAt: new Date().toISOString()
}}];

const base = $('Build OpenAI Request').item.json;
const llm = $json;

function extractText(value) {
  if (!value) return '';
  if (typeof value === 'string') return value;
  if (Array.isArray(value)) return value.map(extractText).filter(Boolean).join('\n');
  if (typeof value === 'object') {
    if (typeof value.text === 'string') return value.text;
    if (typeof value.output_text === 'string') return value.output_text;
    if (typeof value.content === 'string') return value.content;
    if (Array.isArray(value.content)) return extractText(value.content);
    if (Array.isArray(value.output)) return extractText(value.output);
    if (value.message?.content) return extractText(value.message.content);
    if (value.choices) return extractText(value.choices);
  }
  return '';
}

function stripFence(text) {
  return String(text || '').trim().replace(/^```(?:json|csv|xml|markdown)?\s*/i, '').replace(/```$/i, '').trim();
}

function csvEscape(value) {
  const text = String(value ?? '');
  return /[",\n]/.test(text) ? `"${text.replace(/"/g, '""')}"` : text;
}

function rowsToCsv(rows) {
  if (!Array.isArray(rows) || !rows.length) return '';
  const headers = [];
  rows.forEach((row) => Object.keys(row || {}).forEach((key) => { if (!headers.includes(key)) headers.push(key); }));
  return [headers.join(','), ...rows.map((row) => headers.map((key) => csvEscape(row?.[key])).join(','))].join('\n');
}

let rawText = stripFence(extractText(llm));
if (!rawText) throw new Error('LLM output is empty');

let content = rawText;
let markdownContent = '';
let csvContent = '';
let rows = [];
let format = base.targetOutputType === 'service_diagram' ? 'drawio' : 'markdown';
let contentType = base.outputContentType;

if (base.targetOutputType === 'ia') {
  format = 'csv';
  try {
    const parsed = JSON.parse(rawText);
    markdownContent = String(parsed.markdown || '').trim();
    csvContent = String(parsed.csvContent || parsed.csv || '').trim();
    rows = Array.isArray(parsed.rows) ? parsed.rows : [];
    if (!csvContent && rows.length) csvContent = rowsToCsv(rows);
    content = csvContent || rawText;
  } catch {
    csvContent = rawText;
    content = csvContent;
  }
  if (!String(content).trim()) throw new Error('IA CSV output is empty');
}

const log = {
  action: base.action,
  targetOutputType: base.targetOutputType,
  sourcePrdPath: base.sourcePrdPath,
  promptTemplate: base.promptTemplate,
  outputPath: base.outputPath,
  model: base.model,
  status: 'success',
  startedAt: base.receivedAt,
  endedAt: new Date().toISOString(),
  targetRegions: base.targetRegions,
  supportedLanguages: base.supportedLanguages
};

return [{ json: {
  success: true,
  targetOutputType: base.targetOutputType,
  format,
  path: base.outputPath,
  content,
  output: content,
  generatedContent: content,
  markdownContent,
  csvContent,
  rows,
  contentType,
  access: 'private',
  logPath: base.logPath,
  logText: JSON.stringify(log, null, 2),
  metadata: {
    sourcePrdPath: base.sourcePrdPath,
    sourcePrdName: base.sourcePrdName,
    promptTemplate: base.promptTemplate,
    targetRegions: base.targetRegions,
    supportedLanguages: base.supportedLanguages,
    outputLanguage: base.outputLanguage,
    model: base.model,
    createdAt: new Date().toISOString()
  }
}}];
